106→      </div>
107→      <ActionsDropdown
108→        sections={dropdownSections}
109→        open={dropdownOpen}
110→        onClose={onDropdownClose}
111→        triggerRef={actionsTriggerRef}
112→      />
113→    </footer>
114→  );
