 38→function ChevronRight() {
 39→  return (
 40→    <svg
 41→      className="actions-dropdown__chevron"
 42→      width="12"
 43→      height="12"
 44→      viewBox="0 0 12 12"
 45→      fill="none"
 46→    >
 47→      <path
 48→        d="M4.5 2.5L8 6L4.5 9.5"
 49→        stroke="currentColor"
 50→        strokeWidth="1.5"
 51→        strokeLinecap="round"
 52→        strokeLinejoin="round"
 53→      />
 54→    </svg>
 55→  );
 56→}
 57→
 58→function renderSections(
 59→  nonEmptySections: DropdownSection[],
 60→  sectionOffsets: number[],
 61→  activeIndex: number,
 62→  onExecute: (index: number) => void,
 63→  onHover: (index: number) => void
 64→) {
 65→  return nonEmptySections.map((section, sectionIndex) => {
 66→    const offset = sectionOffsets[sectionIndex]!;
 67→    const titleId = section.title ? `section-title-${sectionIndex}` : undefined;
 68→
 69→    return (
 70→      <Fragment key={`section-${sectionIndex}`}>
 71→        {sectionIndex > 0 && (
 72→          <div className="actions-dropdown__separator" role="separator" />
 73→        )}
 74→        <div
 75→          className="actions-dropdown__section"
 76→          role="group"
 77→          aria-labelledby={titleId}
 78→        >
 79→          {titleId && (
 80→            <div
 81→              id={titleId}
 82→              className="actions-dropdown__section-title"
 83→              role="presentation"
 84→            >
 85→              {section.title}
 86→            </div>
 87→          )}
 88→          {section.actions.map((action, actionIndex) => {
 89→            const idx = offset + actionIndex;
 90→            const hasSubmenu = action.submenu && action.submenu.length > 0;
 91→            return (
 92→              <button
 93→                key={`action-${idx}`}
 94→                id={`action-item-${idx}`}
 95→                className={`actions-dropdown__item${idx === activeIndex ? ' actions-dropdown__item--active' : ''}${hasSubmenu ? ' actions-dropdown__item--has-submenu' : ''}`}
 96→                data-dropdown-index={idx}
 97→                role="menuitem"
 98→                type="button"
 99→                aria-haspopup={hasSubmenu ? 'menu' : undefined}
100→                onClick={() => onExecute(idx)}
101→                onMouseEnter={() => onHover(idx)}
102→              >
103→                <span className="actions-dropdown__label">{action.label}</span>
104→                {hasSubmenu ? (
105→                  <ChevronRight />
106→                ) : action.shortcut ? (
107→                  <span className="actions-dropdown__shortcut">
108→                    {action.shortcut}
109→                  </span>
110→                ) : null}
111→              </button>
112→            );
113→          })}
114→        </div>
115→      </Fragment>
116→    );
117→  });
118→}
119→
120→export function ActionsDropdown({
121→  sections,
122→  open,
123→  onClose,
124→  triggerRef,
125→}: ActionsDropdownProps) {
126→  const [activeIndex, setActiveIndex] = useState(0);
127→  const [submenu, setSubmenu] = useState<SubmenuState | null>(null);
128→  const [submenuDirection, setSubmenuDirection] = useState<
129→    'enter' | 'exit' | null
130→  >(null);
131→  const dropdownRef = useRef<HTMLDivElement>(null);
132→
133→  const nonEmptySections = useMemo(
134→    () =>
135→      (submenu ? submenu.sections : sections).filter(s => s.actions.length > 0),
136→    [
137→      sections,
138→      submenu,
139→    ],
140→  );
141→
142→  const flatActions = useMemo(
143→    () => nonEmptySections.flatMap(s => s.actions),
144→    [nonEmptySections],
145→  );
146→
147→  const sectionOffsets = useMemo(() => {
148→    const offsets: number[] = [];
149→    let total = 0;
150→    for (const section of nonEmptySections) {
151→      offsets.push(total);
152→      total += section.actions.length;
153→    }
154→    return offsets;
155→  }, [nonEmptySections]);
156→
157→  useEffect(() => {
158→    if (open && dropdownRef.current) {
159→      setActiveIndex(0);
160→      setSubmenu(null);
161→      setSubmenuDirection(null);
162→      dropdownRef.current.focus();
163→    }
164→  }, [open]);
165→
166→  const openSubmenu = useCallback(
167→    (index: number): boolean => {
168→      const action = flatActions[index];
169→      if (!action?.submenu || action.submenu.length === 0) {
170→        return false;
171→      }
172→      setSubmenuDirection('enter');
173→      setSubmenu({
174→        sections: action.submenu,
175→        parentLabel: action.label,
176→        parentActiveIndex: index,
177→      });
178→      setActiveIndex(0);
179→      return true;
180→    },
181→    [flatActions],
182→  );
183→
184→  const closeSubmenu = useCallback((): boolean => {
185→    if (!submenu) return false;
186→    const restoreIndex = submenu.parentActiveIndex;
187→    setSubmenuDirection('exit');
188→    setSubmenu(null);
189→    setActiveIndex(restoreIndex);
190→    return true;
191→  }, [submenu]);
192→
193→  const executeAction = useCallback(
194→    (index: number) => {
195→      const action = flatActions[index];
196→      if (!action) return;
197→      if (action.submenu && action.submenu.length > 0) {
198→        openSubmenu(index);
199→        return;
200→      }
201→      action.onClick?.();
202→      onClose();
203→    },
204→    [
205→      flatActions,
206→      onClose,
207→      openSubmenu,
208→    ],
209→  );
210→
211→  useEffect(() => {
212→    if (!open) return;
213→
214→    function handleKeyDown(e: KeyboardEvent) {
215→      if (e.key === 'k' && e.metaKey) {
216→        e.preventDefault();
217→        e.stopPropagation();
218→        onClose();
219→        return;
220→      }
221→
222→      if (e.key === 'Escape') {
223→        e.preventDefault();
224→        e.stopPropagation();
225→        if (!closeSubmenu()) {
226→          onClose();
227→        }
228→        return;
229→      }
230→
231→      if (e.key === 'ArrowLeft') {
232→        e.preventDefault();
233→        e.stopPropagation();
234→        closeSubmenu();
235→        return;
236→      }
237→
238→      if (e.key === 'ArrowRight') {
239→        e.preventDefault();
240→        e.stopPropagation();
241→        openSubmenu(activeIndex);
242→        return;
243→      }
244→
245→      if (e.key === 'ArrowDown') {
246→        e.preventDefault();
247→        e.stopPropagation();
248→        setActiveIndex(i => (i < flatActions.length - 1 ? i + 1 : 0));
249→        return;
250→      }
251→
252→      if (e.key === 'ArrowUp') {
253→        e.preventDefault();
254→        e.stopPropagation();
255→        setActiveIndex(i => (i > 0 ? i - 1 : flatActions.length - 1));
256→        return;
257→      }
258→
259→      if (e.key === 'Enter') {
260→        e.preventDefault();
261→        e.stopPropagation();
262→        executeAction(activeIndex);
263→      }
264→    }
265→
266→    window.addEventListener('keydown', handleKeyDown, true);
267→    return () => window.removeEventListener('keydown', handleKeyDown, true);
268→  }, [
269→    open,
270→    activeIndex,
271→    onClose,
272→    executeAction,
273→    openSubmenu,
274→    closeSubmenu,
275→  ]);
276→
277→  useEffect(() => {
278→    if (!open) return;
279→
280→    function handleClickOutside(e: MouseEvent) {
281→      const target = e.target as Node;
282→      if (dropdownRef.current && !dropdownRef.current.contains(target)) {
283→        if (triggerRef?.current?.contains(target)) return;
284→        onClose();
285→      }
286→    }
287→
288→    document.addEventListener('mousedown', handleClickOutside);
289→    return () => document.removeEventListener('mousedown', handleClickOutside);
290→  }, [
291→    open,
292→    onClose,
293→    triggerRef,
294→  ]);
295→
296→  useEffect(() => {
297→    if (!open) return;
298→    const container = dropdownRef.current;
299→    if (!container) return;
300→
301→    const activeElement = container.querySelector<HTMLElement>(
302→      `[data-dropdown-index="${activeIndex}"]`,
303→    );
304→    activeElement?.scrollIntoView({ block: 'nearest' });
305→  }, [
306→    open,
307→    activeIndex,
308→  ]);
309→
310→  useEffect(() => {
311→    if (!submenuDirection) return;
312→    const timer = setTimeout(() => setSubmenuDirection(null), 150);
313→    return () => clearTimeout(timer);
314→  }, [submenuDirection]);
315→
316→  if (!open || flatActions.length === 0) return null;
317→
318→  const slideClass =
319→    submenuDirection === 'enter'
320→      ? ' actions-dropdown__content--slide-left'
321→      : submenuDirection === 'exit'
322→        ? ' actions-dropdown__content--slide-right'
323→        : '';
324→
325→  return (
326→    <div
327→      className="actions-dropdown"
328→      ref={dropdownRef}
329→      role="menu"
330→      aria-label={submenu ? submenu.parentLabel : 'Available actions'}
331→      aria-activedescendant={`action-item-${activeIndex}`}
332→      tabIndex={-1}
333→    >
334→      <div className={`actions-dropdown__content${slideClass}`}>
335→        {submenu && (
336→          <button
337→            className="actions-dropdown__back"
338→            type="button"
339→            role="menuitem"
340→            aria-label={`Back to parent menu from ${submenu.parentLabel}`}
341→            onClick={closeSubmenu}
342→          >
343→            <svg width="12" height="12" viewBox="0 0 12 12" fill="none">
344→              <path
345→                d="M7.5 2.5L4 6L7.5 9.5"
346→                stroke="currentColor"
347→                strokeWidth="1.5"
348→                strokeLinecap="round"
349→                strokeLinejoin="round"
350→              />
351→            </svg>
352→            <span>{submenu.parentLabel}</span>
353→          </button>
354→        )}
355→        {renderSections(
356→          nonEmptySections,
357→          sectionOffsets,
358→          activeIndex,
359→          executeAction,
360→          setActiveIndex,
361→        )}
362→      </div>
363→    </div>
364→  );
365→}
