 1→import {
 2→  type ReactNode,
 3→  useCallback,
 4→  useEffect,
 5→  useRef,
 6→  useState,
 7→} from 'react';
 8→import type { HUDData } from '../components/hud/hud';
 9→
10→const AUTO_DISMISS_MS = 1500;
11→const EXIT_ANIMATION_MS = 150;
12→
13→let nextId = 0;
14→
15→interface ShowHUDOptions {
16→  icon?: ReactNode;
17→  title: string;
18→}
19→
20→export function useHUD() {
21→  const [items, setItems] = useState<HUDData[]>([]);
22→  const timersRef = useRef<Map<string, ReturnType<typeof setTimeout>>>(
23→    new Map(),
24→  );
25→
26→  useEffect(() => {
27→    const timers = timersRef.current;
28→    return () => {
29→      timers.forEach(timer => clearTimeout(timer));
30→      timers.clear();
31→    };
32→  }, []);
33→
34→  const hide = useCallback((id: string) => {
35→    const timer = timersRef.current.get(id);
36→    if (timer) {
37→      clearTimeout(timer);
38→      timersRef.current.delete(id);
39→    }
40→    setItems(prev =>
41→      prev.map(item =>
42→        item.id === id
43→          ? {
44→              ...item,
45→              exiting: true,
46→            }
47→          : item));
48→    const exitTimer = setTimeout(() => {
49→      timersRef.current.delete(`${id}-exit`);
50→      setItems(prev => prev.filter(item => item.id !== id));
51→    }, EXIT_ANIMATION_MS);
52→    timersRef.current.set(`${id}-exit`, exitTimer);
53→  }, []);
54→
55→  const show = useCallback(
56→    (options: ShowHUDOptions) => {
57→      const id = String(nextId++);
58→      const hud: HUDData = {
59→        id,
60→        icon: options.icon,
61→        title: options.title,
62→        exiting: false,
63→      };
64→
65→      setItems(prev => [
66→        hud,
67→        ...prev,
68→      ]);
69→
70→      const timer = setTimeout(() => {
71→        timersRef.current.delete(id);
72→        hide(id);
73→      }, AUTO_DISMISS_MS);
74→      timersRef.current.set(id, timer);
75→
76→      return id;
77→    },
78→    [hide],
79→  );
80→
81→  return {
82→    items,
83→    show,
84→    hide,
85→  };
86→}
