 58→
 59→function loadRecentEmojis(): string[] {
 60→  const stored = storageGet(STORAGE_KEY, isStringArray);
 61→  if (stored) return stored;
 62→
 63→  try {
 64→    const legacy = localStorage.getItem('emoji-picker-recent');
 65→    if (legacy) {
 66→      const parsed: unknown = JSON.parse(legacy);
 67→      if (isStringArray(parsed)) {
 68→        storageSet(STORAGE_KEY, parsed);
 69→        localStorage.removeItem('emoji-picker-recent');
 70→        return parsed;
 71→      }
 72→    }
 73→  } catch {
 74→    // unavailable
 75→  }
 76→  return [];
 77→}
 78→
 79→interface EmojiSection {
 80→  title: string;
 81→  emojis: EmojiEntry[];
 82→}
 83→
 84→const FILTER_SECTIONS: SearchDropdownSection[] = [
 85→  {
 86→    options: [
 87→      {
 88→        label: 'All',
 89→        value: 'all',
 90→      },
 91→    ],
 92→  },
 93→  {
 94→    title: 'Category',
 95→    options: EMOJI_CATEGORIES.map(c => ({
 96→      label: c.label,
 97→      value: c.value,
 98→    })),
 99→  },
100→];
