102→export function EmojiPickerView() {
103→  const nav = useNavigation();
104→  const [query, setQuery] = useState('');
105→  const [filterValue, setFilterValue] = useState('all');
106→  const [activeIndex, setActiveIndex] = useState(0);
107→  const [actionsOpen, setActionsOpen] = useState(false);
108→  const [recentChars, setRecentChars] = useState<string[]>(loadRecentEmojis);
109→  const { items: hudItems, show: showHUD } = useHUD();
110→  const containerRef = useRef<HTMLDivElement>(null);
111→
112→  const emojiLookup = useMemo(() => {
113→    const map = new Map<string, EmojiEntry>();
114→    for (const e of MOCK_EMOJIS) {
115→      map.set(e.char, e);
116→    }
117→    return map;
118→  }, []);
119→
120→  const recentEmojis = useMemo(
121→    () =>
122→      recentChars
123→        .map(char => emojiLookup.get(char))
124→        .filter((e): e is EmojiEntry => e !== undefined),
125→    [
126→      recentChars,
127→      emojiLookup,
128→    ],
129→  );
130→
131→  const filtered = useMemo(() => {
132→    let emojis = MOCK_EMOJIS;
133→    if (filterValue !== 'all') {
134→      emojis = emojis.filter(e => e.category === filterValue);
135→    }
136→    if (query) {
137→      emojis = emojis.filter(
138→        e =>
139→          fuzzyMatch(query, e.name) ||
140→          e.keywords.some(k => fuzzyMatch(query, k)) ||
141→          e.char === query,
142→      );
143→    }
144→    return emojis;
145→  }, [
146→    query,
147→    filterValue,
148→  ]);
149→
150→  const sections = useMemo(() => {
151→    const result: EmojiSection[] = [];
152→
153→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
154→      result.push({
155→        title: 'Recently Used',
156→        emojis: recentEmojis,
157→      });
158→    }
159→
160→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
161→    for (const emoji of filtered) {
162→      const existing = grouped.get(emoji.category);
163→      if (existing) {
164→        existing.push(emoji);
165→      } else {
