278→    function handleKeyDown(e: KeyboardEvent) {
279→      if (totalCount === 0) return;
280→      if (actionsOpen) return;
281→      if (e.metaKey || e.ctrlKey || e.altKey) return;
282→
283→      const isTextInput =
284→        e.target instanceof HTMLInputElement ||
285→        e.target instanceof HTMLTextAreaElement;
286→
287→      switch (e.key) {
288→        case 'ArrowRight': {
289→          if (isTextInput) return;
290→          e.preventDefault();
291→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
292→          break;
293→        }
294→        case 'ArrowLeft': {
295→          if (isTextInput) return;
296→          e.preventDefault();
297→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
298→          break;
299→        }
300→        case 'ArrowDown': {
301→          e.preventDefault();
302→          setActiveIndex(prev => {
303→            const sectionInfo = getSectionInfo(prev);
304→            if (!sectionInfo) return prev;
305→            const { sectionStart, sectionLength } = sectionInfo;
306→            const posInSection = prev - sectionStart;
307→            const row = Math.floor(posInSection / COLUMNS);
308→            const col = posInSection % COLUMNS;
309→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
310→
311→            if (row + 1 < sectionRows) {
312→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
313→              return nextIdx < sectionStart + sectionLength
314→                ? nextIdx
315→                : sectionStart + sectionLength - 1;
316→            }
317→
318→            const nextSectionStart = sectionStart + sectionLength;
319→            if (nextSectionStart < totalCount) {
320→              const nextInfo = getSectionInfo(nextSectionStart);
321→              if (!nextInfo) return prev;
322→              const targetIdx = nextSectionStart + col;
323→              return targetIdx < nextSectionStart + nextInfo.sectionLength
324→                ? targetIdx
325→                : nextSectionStart + nextInfo.sectionLength - 1;
326→            }
327→
328→            return prev;
329→          });
330→          break;
331→        }
332→        case 'ArrowUp': {
333→          e.preventDefault();
334→          setActiveIndex(prev => {
335→            const sectionInfo = getSectionInfo(prev);
336→            if (!sectionInfo) return prev;
337→            const { sectionStart } = sectionInfo;
338→            const posInSection = prev - sectionStart;
339→            const row = Math.floor(posInSection / COLUMNS);
340→            const col = posInSection % COLUMNS;
341→
342→            if (row > 0) {
343→              return sectionStart + (row - 1) * COLUMNS + col;
344→            }
345→
346→            if (sectionStart > 0) {
347→              const prevSectionEnd = sectionStart - 1;
348→              const prevInfo = getSectionInfo(prevSectionEnd);
349→              if (!prevInfo) return prev;
350→              const prevSectionRows = Math.ceil(
351→                prevInfo.sectionLength / COLUMNS,
352→              );
353→              const lastRowStart =
354→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
355→              const targetIdx = lastRowStart + col;
356→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
357→                ? targetIdx
358→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
359→            }
360→
361→            return prev;
362→          });
363→          break;
364→        }
365→        case 'Enter': {
366→          e.preventDefault();
367→          handleCopyEmoji();
368→          break;
369→        }
370→      }
371→    }
372→
373→    window.addEventListener('keydown', handleKeyDown);
374→    return () => window.removeEventListener('keydown', handleKeyDown);
375→  }, [
