 345→          .map(s => ({
 346→            ...s,
 347→            items: s.items.filter(item => !favIds.has(item.id)),
 348→          }))
 349→          .filter(s => s.items.length > 0);
 350→        return [
 351→          {
 352→            title: 'Favorites',
 353→            items: filteredFavs,
 354→          },
 355→          ...dedupedSections,
 356→        ];
 357→      }
 358→      return filteredResult;
 359→    }
 360→
 361→    const pinnedSections: SectionData[] = [];
 362→    const dedupIds = new Set<string>();
 363→
 364→    if (favoriteItems.length > 0) {
 365→      pinnedSections.push({
 366→        title: 'Favorites',
 367→        items: favoriteItems,
 368→      });
 369→      for (const item of favoriteItems) {
 370→        dedupIds.add(item.id);
 371→      }
 372→    }
 373→
 374→    const favSet = new Set(favoriteIds);
 375→    const recentItems = recentIds
 376→      .filter(id => !favSet.has(id))
 377→      .map(id => allFlatItems.find(item => item.id === id))
 378→      .filter((item): item is ListItemData => !!item);
 379→
 380→    if (recentItems.length > 0) {
 381→      pinnedSections.push({
 382→        title: 'Recent Commands',
 383→        items: recentItems,
 384→      });
 385→      for (const item of recentItems) {
 386→        dedupIds.add(item.id);
 387→      }
 388→    }
 389→
 390→    if (pinnedSections.length > 0) {
 391→      const dedupedSections = filteredResult
 392→        .map(s => ({
 393→          ...s,
 394→          items: s.items.filter(item => !dedupIds.has(item.id)),
 395→        }))
 396→        .filter(s => s.items.length > 0);
 397→      return [
 398→        ...pinnedSections,
 399→        ...dedupedSections,
 400→      ];
 401→    }
 402→
 403→    return filteredResult;
