 99→interface StoredSnippet {
100→  id: string;
101→  name: string;
102→  keyword: string;
103→  content: string;
104→  category: string;
105→  tags: {
106→    text: string;
107→    color?: string;
108→  }[];
109→  createdAt: string;
110→}
111→
112→function isStoredTag(value: unknown): value is {
113→  text: string;
114→  color?: string;
115→} {
116→  if (!isRecord(value)) return false;
117→  if (typeof value.text !== 'string') return false;
118→  if ('color' in value && typeof value.color !== 'string') {
119→    return false;
120→  }
121→  return true;
122→}
123→
124→function isStoredSnippetArray(value: unknown): value is StoredSnippet[] {
125→  if (!Array.isArray(value)) return false;
126→  return value.every(
127→    v =>
128→      isRecord(v) &&
129→      typeof v.id === 'string' &&
130→      typeof v.name === 'string' &&
131→      typeof v.keyword === 'string' &&
132→      typeof v.content === 'string' &&
133→      typeof v.category === 'string' &&
134→      typeof v.createdAt === 'string' &&
135→      Array.isArray(v.tags) &&
136→      v.tags.every(isStoredTag),
137→  );
138→}
139→
140→function serializeEntries(entries: SnippetEntry[]): StoredSnippet[] {
141→  return entries.map(e => ({
142→    ...e,
143→    createdAt: e.createdAt.toISOString(),
144→  }));
145→}
146→
147→const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));
148→
149→function isTagColor(value: string): value is TagColor {
150→  return TAG_COLOR_NAMES.has(value);
151→}
152→
153→function deserializeEntries(stored: StoredSnippet[]): SnippetEntry[] {
154→  return stored.map(s => {
155→    const parsed = new Date(s.createdAt);
156→    const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
157→    return {
158→      ...s,
159→      category: isSnippetCategory(s.category) ? s.category : 'general',
160→      tags: s.tags.map(t => ({
161→        text: t.text,
162→        color: t.color && isTagColor(t.color) ? t.color : undefined,
163→      })),
164→      createdAt,
165→    };
166→  });
167→}
